coverRule:
@js:
var 分隔符="&&&";
var 替换分割="%%%"
//作者规则与封面规则后面可以跟替换净化
//目前覆盖起点&&&晋江&&&长佩&&&纵横
//搜索地址:::列表规则:::作者规则:::封面规则
var all="https://m.qidian.com/soushu/书名.html:::class.y-list__item:::@css:*[class^=_searchBookAuthor]@text%%%作者\\s*:::tag.a@tag.img@data-src%%%/\\d{2,3}$&&&http://android.jjwxc.net/androidapi/search?keyword=书名:::$.items[*]:::$.authorname:::$.cover&&&https://www.gongzicp.com/webapi/search/novels?k=书名:::$.data.list[*]:::$.novel_author:::$.novel_cover%%%\\?.*&&&https://search.zongheng.com/search/book?keyword=书名&sort=&pageNo=1&pageNum=20&isFromHuayu=0:::$.data.datas.list[*]:::$.authorName:::$.coverUrl%%%^%%%https://static.zongheng.com/upload/";

function searchCoverG(){
	function ti(规则){
		let 规则判断=规则.match(/^\$|\/\/|@css|@json/i)?"":"@@";
		let r=规则.split(替换分割);
		if (r[2]!=undefined&&r[1]!=undefined){
			let r1=r[1];
			let r2=r[2];
			let reg=new RegExp(r1,'g');
			return String(java.getString(规则判断+r[0])).replace(reg,r2)
		}else if(r[2]==undefined&&r[1]!=undefined){
			r1=r[1];
			reg=new RegExp(r[1],'g');
			return String(java.getString(规则判断+r[0])).replace(reg,'')
		}else{
			return String(java.getString(规则判断+r[0]))
		}
	};
	rrr=new RegExp("(?:"+分隔符+")*$");
	all=String(all.replace(rrr,'')+分隔符);
	var cover="";
	var list=all.split("&&&");
	for (i=0;i<list.length-1;i++){
		var l=list[i].split(":::");
		let 搜索地址=l[0];
		列表规则=l[1];
		作者规则=l[2];
		封面规则=l[3];
		搜索地址=搜索地址.replace(/书名/,book.name);
		html=java.ajax(搜索地址);
		java.setContent(html);
		规则判断=列表规则.match(/^\$|\/\/|@css|@json/i)?"":"@@";
		列表=java.getElements(规则判断+列表规则);
		for (j in 列表){
			java.setContent(列表[j]);
			author=ti(作者规则).replace(/<\/font.*?>/gi,'');
			if (搜索地址.match(/jjwxc/)&&author.match(/\*\*/)){
				author1=author.replace(/\*{2,}.*/g,'');
				author2=author.replace(/.\*{2,}/,'');
				areg=new RegExp("^"+author1);
				areg2=new RegExp(author2+"$");
				if (author.match(areg)&&author.match(areg2)){
					cover=ti(封面规则);
					break
				}
			}
			if (author==book.author){
				cover=ti(封面规则);
				break
			}
			if (cover!=""){
				break
			}
		}
		if (cover!=""){
			break
		}
	}
	return cover
};

function searchCoverL(){
	var key=book.name;
	var url1=`https://pre-api.tuishujun.com/api/searchBook?search_value=${key}&page=1&pageSize=20`;
	var url2=`http://m.ypshuo.com/api/novel/search?keyword=${key}&searchType=1&page=1`;
	var [rr1,rr2]=java.ajaxAll([url1,url2]).map(r=>r.body());
	function jjson(str,rule){
		try{
			return com.jayway.jsonpath.JsonPath.read(str,rule)
		}catch(e){
			return []
		}
	};
	rr1=jjson(rr1,'$.data.data[*]');
	rr2=jjson(rr2,'$.data.data[*]');
	var na=String(book.name),au=String(book.author);
	for (let char of rr1){
		if (na.includes(char.title+'')){
			let au2=char.author_nickname+'';
			if (au.includes(au2)||au2.includes(au)){
				return char.cover
			}
		}
	};
	for (let char of rr2){
		if (na.includes(char.novel_name+'')){
			let au2=char.author_name+'';
			if (au.includes(au2)||au2.includes(au)){
				return char.novel_img
			}
		}
	};
	return ''
};

function svgCover(){
	var 背景色="",文字色="",作者色="";
	try{背景色="#"+String(java.getThemeConfigMap()["backgroundColor"]).match(/.{6}$/)[0];文字色="#"+String(java.getThemeConfigMap()["accentColor"]).match(/.{6}$/)[0];作者色=文字色}catch(e){}
	var 书名=String(book.name).replace(/\s/g,''),作者=String(book.author).replace(/\s/g,'');
	var 实际宽度=300,实际高度=400,字体大小=28,行高=字体大小*1.4;
	var 处理书名=(文本,最大行数,每行最大字符)=>{
		if(!文本)return"";
		var 结果='',当前行='',最大总字数=每行最大字符*最大行数;
		for(var i=0;i<Math.min(文本.length,最大总字数);i++){
			当前行+=文本[i];
			if(当前行.length>=每行最大字符||i==Math.min(文本.length,最大总字数)-1){
				var 当前行数=结果.split('\n').length;
				if(当前行数<最大行数-1){结果+=当前行+(i<Math.min(文本.length,最大总字数)-1?'\n':'');当前行=''}
				else{结果+=当前行.substring(0,Math.max(1,当前行.length-1))+'...';break}
			}
		}
		return 结果||文本.substring(0,Math.min(文本.length,每行最大字符))
	};
	var 处理作者=(文本,作者最大字数)=>{
		if(!文本)return"";
		return 文本.length<=作者最大字数?文本:文本.substring(0,作者最大字数-1)+"..."
	};
	var 处理后的书名=处理书名(书名,4,10),处理后的作者=处理作者(作者,10);
	var 书名行数=处理后的书名.includes('\n')?处理后的书名.split('\n').length:1;
	var 作者行高=字体大小*0.8*1.3,书名区域高度=书名行数*行高,作者区域高度=处理后的作者?作者行高:0;
	var 顶部边距=Math.max(50,(实际高度-书名区域高度-作者区域高度)/2);
	var 书名SVG=处理后的书名.split('\n').map((行,i)=>`<text text-anchor="middle" font-size="${字体大小}" fill="${文字色||'#333333'}" font-weight="bold" dy="${i*行高}">${行}</text>`).join('');
	var 作者SVG=处理后的作者?`<text text-anchor="middle" font-size="${字体大小*0.8}" fill="${作者色||'#666666'}" dy="${书名区域高度+字体大小*0.4}">${处理后的作者}</text>`:'';
	var svg=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${实际宽度} ${实际高度}" width="${实际宽度}" height="${实际高度}"><rect width="${实际宽度}" height="${实际高度}" fill="${背景色||'#F0F8FF'}"/><g transform="translate(${实际宽度/2},${顶部边距+行高/2})">${书名SVG}${作者SVG}</g></svg>`;
	return"data:image/svg+xml;base64,"+java.base64Encode(svg)
};

var cover=searchCoverG()||searchCoverL()||svgCover();
cover=/^\/\//.test(cover)?"https:"+cover:cover;
cover=cover.replace(/(https?:\/\/.*?)(\/.*)/,'$1$2,{"headers":{"referer":"$1"}}');
cover
